function maxTwinSum(head) {
    let sum = 0, max_sum = 0, i = 0;
    let slow = head, fast = head;

    while (fast && fast.next) {
        fast = fast.next.next;
        i++;
    }

    for (let j = 0; j < i; j++) {
        sum = slow.val + fast.val;
        max_sum = Math.max(max_sum, sum);
        slow = slow.next;
        fast = fast.prev;
    }

    return max_sum;
