function longestPalindrome(words) {
    let dict = {};
    let result = 0;
    let hasOdd = false;

    for (let word of words) {
        dict[word[0]] = (dict[word[0]] || 0) + 1;
        dict[word[1]] = (dict[word[1]] || 0) + 1;
    }

    for (let count of Object.values(dict)) {
        result += Math.floor(count / 2) * 2;
        hasOdd |= count % 2;
    }

    return result + (hasOdd ? 1 : 0);
