function robotInstructions(n, startPos, s) {
    let answer = new Array(s.length).fill(0);

    for (let idx = 0; idx < s.length; ++idx) {
        let row = startPos[0];
        let col = startPos[1];

        for (let i = idx; i < s.length; ++i) {
            let move = s[i];
            if (move === 'L') --col;
            else if (move === 'R') ++col;
            else if (move === 'U') --row;
            else if (move === 'D') ++row;

            if (row < 0 || row >= n || col < 0 || col >= n) {
                break;
            }

            answer[idx]++;
        }
    }

    return answer;
},"diGraph  {

