function maxScore(scores, edges) {
    const adj_list = new Array(scores.length).fill(null).map(() => []);
    let result = -1;

    for (const edge of edges) {
        adj_list[edge[0]].push(edge[1]);
        adj_list[edge[1]].push(edge[0]);
    }

    for (const edge of edges) {
        for (const neighbor of adj_list[edge[0]]) {
            for (const next of adj_list[edge[1]]) {
                if (next !== neighbor && next !== edge[0]) {
                    result = Math.max(result, scores[edge[0]] + scores[edge[1]] + scores[neighbor] + scores[next]);
                }
            }
        }
    }

    return result;
},"diGraph  {

