function numOfBeams(bank) {
    let m = bank.length;
    let n = bank[0].length;
    let beams = 0;

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (bank[i][j] == '1') {
                let k = j + 1;
                while (k < n && bank[i][k] != '1') {
                    beams += bank[i][k] == '0' ? 1 : 0;
                    k++;
                }
                k = i + 1;
                while (k < m && bank[k][j] != '1') {
                    beams += bank[k][j] == '0' ? 1 : 0;
                    k++;
                }
            }
        }
    }

    return beams;
},"diGraph  {

