function kHighestRankedItems(grid, pricing, start, k) {
    const m = grid.length, n = grid[0].length;
    const directions = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    const res = [];
    const pq = [];
    const visited = Array.from({length: m}, () => Array(n).fill(false));

    pq.push([0, -grid[start[0]][start[1]], start[0], start[1]]);
    visited[start[0]][start[1]] = true;

    while (pq.length > 0 && k > 0) {
        const size = pq.length;
        for (let i = 0; i < size; i++) {
            const curr = pq.shift();
            const [steps, price, row, col] = curr;

            if (price >= pricing[0] && price <= pricing[1]) {
                res.push([row, col]);
                k--;
            }

            for (const [dr, dc] of directions) {
                const newRow = row + dr, newCol = col + dc;
                if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n && !visited[newRow][newCol]) {
                    visited[newRow][newCol] = true;
                    pq.push([steps + 1, -grid[newRow][newCol], newRow, newCol]);
                }
            }
        }
        pq.sort(([aSteps, aPrice], [bSteps, bPrice]) => aSteps * 1000000 - aPrice - (bSteps * 1000000 - bPrice));
    }

    return res;
},"diGraph  {

