const MOD = 10**9 + 7;

function corridorWays(corridor) {
    const n = corridor.length;
    let dp = new Array(n + 1).fill(0);
    dp[0] = 1;

    let seats = 0;
    for (let i = 0; i < n; i++) {
        if (corridor[i] === 'S') {
            seats++;
            if (seats % 2 === 0) {
                dp[i + 1] = dp[Math.max(0, i - 1)];
            }
            dp[i + 1] = (dp[i] + dp[i + 1]) % MOD;
        } else {
            dp[i + 1] = dp[i];
        }
    }

    return dp[n];
},"diGraph  {

