function minSwaps(nums) {
    let ones = 0, maxOnes = 0, currOnes = 0, left = 0;

    for (let num of nums) {
        ones += num;
    }

    for (let right = 0; right < nums.length; ++right) {
        currOnes += nums[right];

        if (right - left + 1 > ones) {
            currOnes -= nums[left];
            ++left;
        }

