function minimumTimeForTrips(time, totalTrips) {
    time.sort((a, b) => a - b);

    let start = 0, end = time[time.length - 1] * totalTrips;
    while (start < end) {
        let mid = start + Math.floor((end - start) / 2);
        let trips = 0;
        for (let t of time) {
            trips += Math.floor(mid / t);
        }
        if (trips < totalTrips) {
            start = mid + 1;
        } else {
            end = mid;
        }
    }

    return start;
