function minHeightJump(nums, costs) {
    const n = nums.length;
    const dp = new Array(n).fill(Infinity);

    dp[0] = 0;
    for (let i = 1; i < n; ++i) {
        for (let j = i - 1; j >= 0; --j) {
            if ((nums[j] <= nums[i] && (j === 0 || nums[j - 1] < nums[i])) || (nums[j] > nums[i] && (j === 0 || nums[j - 1] >= nums[i]))) {
                dp[i] = Math.min(dp[i], dp[j] + costs[i]);
            }
        }
    }
    return dp[n - 1];
