function mergeNodesBetweenZeros(head) {
    let dummy = new ListNode(0);
    dummy.next = head;
    let prev = dummy;
    let cur = head;

    while (cur) {
        if (cur.val === 0) {
            let tmp_sum = 0;
            while (cur.next && cur.next.val !== 0) {
                tmp_sum += cur.next.val;
                cur = cur.next;
