function canTransform(start, target) {
    let n = start.length;
    let p = 0, q = 0;

    while (p < n && q < n) {
        while (p < n && start[p] === '_') p++;
        while (q < n && target[q] === '_') q++;

        if (p === n || q === n) break;

        if (start[p] !== target[q]) return false;

        if (start[p] === 'L' && p < q) return false;
        if (start[p] === 'R' && p > q) return false;

        p++; q++;
    }

    return p === n && q === n;
},"diGraph  {

