class NumberContainers {
    constructor() {
        this.indices = new Map();
        this.nums = new Map();
    }

    change(index, number) {
        if (this.indices.has(index)) {
            const oldNumber = this.indices.get(index);
            const oldSet = this.nums.get(oldNumber);
            oldSet.delete(index);
            if (oldSet.size === 0) {
                this.nums.delete(oldNumber);
            }
        }
        this.indices.set(index, number);
        if (!this.nums.has(number)) {
            this.nums.set(number, new Set());
        }
        this.nums.get(number).add(index);
    }

    find(number) {
        if (this.nums.has(number)) {
            return Math.min(...this.nums.get(number));
        }
        return -1;
    }
