function shortestUnrollableSequence(rolls, k) {
    const count = new Array(k + 1).fill(0);
    for (const roll of rolls) {
        count[roll]++;
    }

    let len = 1;
    while (true) {
        let max_subsequences = 1;
        for (let i = 1; i <= k; i++) {
            max_subsequences *= count[i] + (len === 1 ? 1 : 0);
        }

        if (max_subsequences < len * rolls.length) {
            return len;
        }

        len++;
    }
},"diGraph  {

