function minDaysToCompleteTasks(tasks, space) {
    const taskLastComplete = {};
    let days = 0;

    for (const task of tasks) {
        if (task in taskLastComplete) {
            const passedDays = days - taskLastComplete[task];
            if (passedDays < space) {
                days += space - passedDays;
            }
        }
        days++;
        taskLastComplete[task] = days;
    }

    return days;
