function maxNodesWithoutRestricted(n, edges, restricted) {
    const tree = new Map();
    const blockedNodes = new Set(restricted);

    for (const [a, b] of edges) {
        if (!tree.has(a)) tree.set(a, []);
        if (!tree.has(b)) tree.set(b, []);
        tree.get(a).push(b);
        tree.get(b).push(a);
    }

    let maxNodes = 0;

    function dfs(node, depth, parent) {
        if (blockedNodes.has(node)) return;
        maxNodes = Math.max(maxNodes, depth);
        for (const child of tree.get(node)) {
            if (child !== parent) dfs(child, depth + 1, node);
        }
    }

    dfs(0, 1, -1);
    return maxNodes;
