function maxSegSumAfterQueries(nums, removeQueries) {
    const n = nums.length;
    const answer = new Array(n);
    const removed = new Set([-1, n]);

    let currentSum = 0, maxSum = 0;
    for (const x of nums) {
        if (x > 0) currentSum += x;
        else {
            maxSum = Math.max(maxSum, currentSum);
            currentSum = 0;
        }
    }
    maxSum = Math.max(maxSum, currentSum);

    for (let i = 0; i < n; ++i) {
        const removeIdx = removeQueries[i];
        answer[i] = maxSum;
        nums[removeIdx] = -nums[removeIdx];

        const leftIdx = Math.max(...removed).filter(x => x < removeIdx);
        const rightIdx = Math.min(...removed).filter(x => x > removeIdx);

        let leftSum = 0, rightSum = 0;
        for (let j = rightIdx - 1; j >= 0; --j) {
            if (nums[j] < 0) leftSum -= nums[j];
            else break;
        }
        for (let j = leftIdx + 1; j < n; ++j) {
            if (nums[j] < 0) rightSum -= nums[j];
            else break;
        }

        maxSum -= Math.max(0, leftSum - (-nums[removeIdx]));
        maxSum -= Math.max(0, rightSum - (-nums[removeIdx]));
        maxSum += Math.max(0, leftSum + rightSum - (-nums[removeIdx]));

        removed.add(removeIdx);
    }

    return answer;
},"diGraph  {

