function minTrainingHours(initialEnergy, initialExperience, energy, experience) {
    const n = energy.length;
    let ans = 1e9;
    for (let expGain = 0; expGain <= initialEnergy + initialExperience; ++expGain) {
        let trainingHours = expGain;
        let energyLeft = initialEnergy - expGain;
        let currExperience = initialExperience + expGain;

        for (let i = 0; i < n; ++i) {
            while (currExperience <= experience[i] || energyLeft <= energy[i]) {
                energyLeft--;
                trainingHours++;
            }
            energyLeft -= energy[i];
            currExperience += experience[i];
        }
        ans = Math.min(ans, trainingHours);
    }
    return ans;
},"diGraph  {

