function findMedian(grid) {
    const m = grid.length, n = grid[0].length;
    let low = 1, high = 1e6;

    while (low < high) {
        const mid = low + ((high - low) >> 1);
        let count = 0;
        for (let i = 0; i < m; ++i) {
            count += countElements(grid[i], mid);
        }

        if (count < ((m * n) >> 1) + 1) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }

    return low;
}

