    const m = matrix.length;
    const n = matrix[0].length;
    let maxCovered = 0;

    for (let i = 0; i < (1 << n); ++i) {
        if (i.toString(2).split('1').length - 1 === numSelect) {
            let covered = 0;
            for (let row = 0; row < m; ++row) {
                for (let col = 0; col < n; ++col) {
                    if ((matrix[row][col] === 1) && (i & (1 << col))) {
                        covered++;
                        break;
