function maxConsecutiveRobots(chargeTimes, runningCosts, budget) {
    const n = chargeTimes.length;
    let maxRobots = 0;
    for (let i = 0; i < n; i++) {
        let maxCharge = 0;
        let runningSum = 0;
        for (let j = i; j < n; j++) {
            maxCharge = Math.max(maxCharge, chargeTimes[j]);
            runningSum += runningCosts[j];
            const cost = maxCharge + runningSum * (j - i + 1);
            if (cost <= budget)
                maxRobots = Math.max(maxRobots, j - i + 1);
            else
                break;
        }
    }
    return maxRobots;
},"diGraph  {

