const MOD = 1e9 + 7;
const MAX = 1001;

function ways(startPos, endPos, k, dp) {
    if (k === 0) return startPos === endPos ? 1 : 0;
    if (startPos < 0 || endPos < 0 || startPos >= MAX || endPos >= MAX) return 0;

    if (dp[startPos][k] !== -1) return dp[startPos][k];

    const left = ways(startPos - 1, endPos, k - 1, dp);
    const right = ways(startPos + 1, endPos, k - 1, dp);

    return dp[startPos][k] = (left + right) % MOD;
}

function numberOfWays(startPos, endPos, k) {
    const dp = Array.from({ length: MAX }, () => Array(k + 1).fill(-1));
    return ways(startPos, endPos, k, dp)
},"diGraph  {

