function mostVisitedRoom(n, meetings) {
    meetings.sort((a, b) => a[0] - b[0]);
    const pq = [];
    const rooms = Array(n).fill(0);

    for (const [start, end] of meetings) {
        while (pq.length && pq[0][0] <= start) {
            const [_, room] = pq.shift();
            rooms[room]++;
        }
        pq.push([end, pq.length % n]);
        pq.sort((a, b) => a[0] - b[0]);
    }

    return rooms.indexOf(Math.max(...rooms));
},"diGraph  {

