    const n = nums.length;
    const dp = new Map();
    let ans = 0;

    for (const num of nums) {
        let temp = 0;
        const key = [...dp.keys()].reverse().find(key => key <= num - k);
        if (key !== undefined) {
            temp = dp.get(key);
