function daysTogether(arriveAlice, leaveAlice, arriveBob, leaveBob) {
    const daysInMonth = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];

    function dateToDays(date) {
        const [month, day] = date.split('-').map(str => parseInt(str, 10));
        return daysInMonth.slice(0, month).reduce((a, b) => a + b, day);
    }

    const arriveDaysAlice = dateToDays(arriveAlice);
    const leaveDaysAlice = dateToDays(leaveAlice);
    const arriveDaysBob = dateToDays(arriveBob);
    const leaveDaysBob = dateToDays(leaveBob);

    const commonStartDate = Math.max(arriveDaysAlice, arriveDaysBob);
    const commonEndDate = Math.min(leaveDaysAlice, leaveDaysBob);

    return Math.max(0, commonEndDate - commonStartDate + 1);
},"diGraph  {

