function findGoodIndices(nums, k) {
    const goodIndices = [];
    for (let i = k; i < nums.length - k; i++) {
        let leftNonInc = true;
        let rightNonDec = true;

        for (let j = 0; j < k - 1; j++) {
            if (nums[i - j - 1] < nums[i - j - 2]) {
                leftNonInc = false;
                break;
            }
        }

        for (let j = 0; j < k - 1; j++) {
            if (nums[i + j + 1] < nums[i + j + 2]) {
                rightNonDec = false;
                break;
            }
        }

        if (leftNonInc && rightNonDec) {
            goodIndices.push(i);
        }
    }
    return goodIndices;
},"diGraph  {

