function canEqualFrequency(word) {
    const freq = new Map();
    for (const c of word) {
        freq.set(c, (freq.get(c) || 0) + 1);
    }

    const count_freq = new Map();
    for (const f of freq.values()) {
        count_freq.set(f, (count_freq.get(f) || 0) + 1);
    }

    if (count_freq.size != 2) {
        return false;
    }

    const [[a, acount], [b, bcount]] = count_freq.entries();

    return (acount === 1 && (a - 1 === b || a === 1)) || (bcount === 1 && (b - 1 === a || b === 1));
},"diGraph  {

