function dfs(node, parent, bob, time, aliceIncome, amount, tree) {
    if (time < bob || amount[node] >= 0) {
        aliceIncome.val += amount[node];
    } else {
        aliceIncome.val += amount[node] / 2;
    }
    amount[node] = 0;
    let isLeaf = true;
    for (let child of tree[node]) {
        if (child !== parent) {
            isLeaf = false;
            const tempIncome = {val: aliceIncome.val};
            dfs(child, node, bob, time + 1, tempIncome, amount, tree);
        }
    }
    if (isLeaf) {
        aliceIncome.max = Math.max(aliceIncome.max, aliceIncome.val);
    }
}

