function splitMessage(message, limit) {
    let n = message.length;
    let a = (limit - 3) * (n / (limit - 3)) - n;
    let b = n / (limit - 3);
    if ((n + b + a) % (limit - 2) !== 0) 
        return [];
    let num_parts = (n + b + a) / (limit - 2);
    let result = [];
    for (let i = 0, k = 1, cnt = 0; i < n || k <= num_parts;) {
        let temp = "";
        while (cnt < limit - 3) {
            cnt++;
            temp += message[i++];
            if (i === n) break;
        }
        cnt = 0;
        temp += `${k}/${num_parts} `;
        k++;
        result.push(temp);
    }
    return result;
},"diGraph  {

