function numBeautifulPartitions(s, k, minLength) {
    const MOD = 1e9 + 7;
    const primes = new Set(['2', '3', '5', '7']);
    const n = s.length;
    const dp = Array.from({ length: n + 1 }, () => Array(k + 1).fill(0));
    dp[0][0] = 1;

    for (let i = 1; i <= n; i++) {
        for (let j = 1; j <= k; j++) {
            for (let l = minLength; l <= i && i - l >= j - 1; l++) {
                if (primes.has(s[i - l]) && !primes.has(s[i - 1])) {
                    dp[i][j] += dp[i - l][j - 1];
                    if (dp[i][j] >= MOD) dp[i][j] -= MOD;
                }
            }
        }
    }

    return dp[n][k];
},"diGraph  {

