    const tree = new Map();

    for (const edge of edges) {
        if (!tree.has(edge[0])) {
            tree.set(edge[0], []);
        }

        if (!tree.has(edge[1])) {
            tree.set(edge[1], []);
        }

        tree.get(edge[0]).push(edge[1]);
        tree.get(edge[1]).push(edge[0]);
    }

    let firstMax = 0;
