function min_penalty(customers) {
    const n = customers.length;
    let open_penalty = 0, closed_penalty = 0;

    for (const c of customers) {
        if (c === 'N')
            open_penalty++;
        else
            closed_penalty++;
    }

    let result = closed_penalty;
    let penalty = closed_penalty;

    for (const c of customers) {
        if (c === 'N')
            penalty--;
        else
            penalty++;

        result = Math.min(result, penalty);
    }

    return result;
