class Allocator {
    constructor(n) {
        this.mem = new Array(n).fill(0);
    }

    allocate(size, mID) {
        let start = -1, count = 0;
        for (let i = 0; i <= this.mem.length; ++i) {
            if (i < this.mem.length && this.mem[i] === 0) {
                if (start === -1) start = i;
                count++;
            } else {
                if (count >= size) {
                    for (let j = start; j < start + size; j++) {
                        this.mem[j] = mID;
                    }
                    return start;
                }
                start = -1;
                count = 0;
            }
        }
        return -1;
    }

    free(mID) {
        let count = 0;
        for (let i = 0; i < this.mem.length; ++i) {
            if (this.mem[i] === mID) {
                count++;
                this.mem[i] = 0;
            }
        }
        return count;
    }
