    const m = grid.length;
    const n = grid[0].length;
    const dx = [-1, 0, 1, 0];
    const dy = [0, 1, 0, -1];

    function dfs(x, y, q, visited) {
        if (0 <= x && x < m && 0 <= y && y < n && grid[x][y] < q && !visited.has(`${x},${y}`)) {
            visited.add(`${x},${y}`);
            let points = 1;
