function minMinutes(s, k) {
    let n = s.length;
    let left_counts = new Array(3).fill(0);
    let right_counts = s.split('').map(c => (c.charCodeAt() - 'a'.charCodeAt())).reduce((acc, idx) => {
        acc[idx]++;
        return acc;
    }, new Array(3).fill(0));

    let ans = n, total = 0;
    let l = 0, r = n - 1;
    while (l < r) {
        while (l < r && left_counts[s.charCodeAt(l) - 'a'.charCodeAt()] < k && 
                       right_counts[s.charCodeAt(r) - 'a'.charCodeAt()] < k) {
            let need_left = Math.max(0, k - left_counts[s.charCodeAt(l) - 'a'.charCodeAt()]);
            let need_right = Math.max(0, k - right_counts[s.charCodeAt(r) - 'a'.charCodeAt()]);
            if (need_left <= need_right) {
                total += need_left;
                l++;
                left_counts[s.charCodeAt(l) - 'a'.charCodeAt()]++;
                right_counts[s.charCodeAt(l) - 'a'.charCodeAt()]--;
            } else {
                total += need_right;
                r--;
                right_counts[s.charCodeAt(r) - 'a'.charCodeAt()]--;
                left_counts[s.charCodeAt(r) - 'a'.charCodeAt()]++;
            }
        }
        ans = Math.min(ans, total);
        if (l + 1 < s.length()) {
            total -= left_counts[s.charCodeAt(l) - 'a'.charCodeAt()];
            left_counts[s.charCodeAt(l) - 'a'.charCodeAt()]--;
            right_counts[s.charCodeAt(l + 1) - 'a'.charCodeAt()]++;
            l++;
        } else break;
    }
    if (left_counts.every(cnt => cnt >= k)) {
        return ans;
    }
    return -1;
},"diGraph  {

