    const n = nums.length;
    const maxXOR = 1024;
    const counter = new Array(maxXOR).fill(0);

    for (const num of nums) {
        counter[num % maxXOR]++;
    }

    let xor_beauty = 0;
    for (let i = 0; i < maxXOR; i++) {
        for (let j = i; j < maxXOR; j++) {
            const k = (i | j) & (~(i ^ j));
            if (k < maxXOR && k >= j) {
                let count = counter[i] * counter[j] * (i === j ? 1 : 2);
                if (k !== i && k !== j) {
                    count *= counter[k];
                }
                xor_beauty ^= count;
            }
        }
    }

    return xor_beauty;
