        this.collection = [];
    }

    enqueue(element, priority) {
        if (this.isEmpty()) {
            this.collection.push({ element: element, priority: priority });
        } else {
            let added = false;
            for (let i = 0; i < this.collection.length; i++) {
                if (priority < this.collection[i].priority) {
                    this.collection.splice(i, 0, { element: element, priority: priority });
                    added = true;
