function dfs(u, p, adj, price, dp) {
  dp[u] = [[price[u], 0], [price[u], 0]];

  for (const v of adj[u]) {
    if (v == p) continue;
    dfs(v, u, adj, price, dp);
    const tmpF = [dp[v][0][0] + price[u] - dp[v][1][0], dp[v][0][1]].sort((a, b) => a - b);
    const tmpS = [dp[v][1][0] + price[u] - dp[v][0][0], dp[v][1][1]].sort((a, b) => a - b);

    dp[u][0] = tmpF;
    dp[u][1] = tmpS;
  }
}

