    const n = weights.length;
    const prefixSum = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefixSum[i + 1] = prefixSum[i] + weights[i];
    }
    const dp = new Array(n).fill(null).map(() => new Array(k + 1).fill(-1000000000));
