        for (let j = 2; j <= Math.min(i + 1, k); j++) {
            for (let q = 1; q <= i - j + 2; q++) {
                dp[i][j] = Math.max(dp[i][j], dp[i - q][j - 1] + weights[i] + weights[i - q]);
