function shortestSubstringQueries(s, queries) {
    const n = s.length;
    const dp = new Map();

    for (let i = 0, val = 0, mask = 0; i < n; i++) {
        mask |= 1 << (s[i] - '0');
        val = (val << 1) | (s[i] - '0');

        for (let j = 0; j <= 9 && i + 1 - (1 << j) >= 0; j++) {
            const newVal = val & ((1 << (j + 1)) - 1);
