    const visited = Array.from({ length: m }, () => new Array(n).fill(1000000));

    const dx = [-1, 0, 1, 0];
    const dy = [0, 1, 0, -1];

    visited[0][0] = 0;

    const q = [[0, 0]];

    while (q.length) {
        const [x, y] = q.shift();

        for (let i = 0; i < 4; i++) {
            const nx = x + dx[i];
            const ny = y + dy[i];

            if (nx >= 0 && nx < m && ny >= 0 && ny < n) {
                const t = Math.max(grid[nx][ny], visited[x][y] + 1);
                if (visited[nx][ny] > t) {
                    visited[nx][ny] = t;
                    q.push([nx, ny]);
                }
            }
        }
    }

    return visited[m - 1][n - 1] === 1000000 ? -1 : visited[m - 1][n - 1];
},"diGraph  {

