    let even = new Array(20).fill(0);
    even[0] = 1;

    for (const num of nums) {
        let parity = (num >>> 0).toString(2).split('1').length % 2;
        let tempNum = num;
        for (let i = 19; i >= 0; i--) {
            const mask = 1 << i;
            if (tempNum & mask) {
                if (parity) {
                    [odd[i], even[i]] = [even[i], odd[i]];
