class Task {
    constructor(id, description, dueDate, tags, completed) {
        this.id = id;
        this.description = description;
        this.dueDate = dueDate;
        this.tags = tags;
        this.completed = completed;
    }
}

class TodoList {
    constructor() {
        this.taskId = 1;
        this.tasks = {};
    }

    addTask(userId, taskDescription, dueDate, tags) {
        if (!this.tasks[userId]) {
            this.tasks[userId] = [];
        }
        const task = new Task(this.taskId, taskDescription, dueDate, tags, false);
        this.tasks[userId].push(task);
        this.taskId++;
        return this.taskId - 1;
    }

    getAllTasks(userId) {
        if (!this.tasks[userId]) {
            return [];
        }
        const userTasks = this.tasks[userId].slice().sort((a, b) => a.dueDate - b.dueDate);
        const res = userTasks.filter(task => !task.completed).map(task => task.description);
        return res;
    }

    getTasksForTag(userId, tag) {
        if (!this.tasks[userId]) {
            return [];
        }
        const userTasks = this.tasks[userId].slice().sort((a, b) => a.dueDate - b.dueDate);
        const res = userTasks.filter(task => !task.completed && task.tags.includes(tag)).map(task => task.description);
        return res;
    }

    completeTask(userId, taskId) {
        if (!this.tasks[userId]) {
            return;
        }
        for (let task of this.tasks[userId]) {
            if (task.id === taskId) {
                task.completed = true;
                break;
            }
        }
    }
},"diGraph  {

