function shortestCycleLength(n, edges) {
    const graph = Array.from({ length: n }, () => []);
    for (const [u, v] of edges) {
        graph[u].push(v);
        graph[v].push(u);
    }

    let shortestCycle = n + 1;
    for (let start = 0; start < n; ++start) {
        const dist = new Array(n).fill(n + 1);
        dist[start] = 0;
        const queue = [start];

        while (queue.length) {
            const cur = queue.shift();
            for (const neigh of graph[cur]) {
                if (dist[neigh] === n + 1) {
                    dist[neigh] = dist[cur] + 1;
                    queue.push(neigh);
                } else if (dist[neigh] >= dist[cur] - 1) {
                    shortestCycle = Math.min(shortestCycle, dist[cur] + dist[neigh] + 1);
                }
            }
        }
    }

    return shortestCycle === n + 1 ? -1 : shortestCycle;
