function longestBalancedSubstring(s) {
    let max_len = 0;
    let zeros = 0;
    let ones = 0;
    for (const c of s) {
        if (c === '0') {
            zeros++;
        } else {
            ones++;
        }
        if (zeros === ones) {
            max_len = Math.max(max_len, zeros * 2);
        } else if (zeros > ones) {
            zeros = ones = 0;
        }
    }
    zeros = ones = 0;
    for (let i = s.length - 1; i >= 0; --i) {
        if (s[i] === '0') {
            zeros++;
        } else {
            ones++;
        }
        if (zeros === ones) {
            max_len = Math.max(max_len, zeros * 2);
        } else if (zeros < ones) {
            zeros = ones = 0;
        }
    }
    return max_len;
},"diGraph  {

