function distinctRowsFrom(nums) {
    const rows = [];

    for(const num of nums) {
        let inserted = false;
        for(const row of rows) {
            if(!row.has(num)) {
                row.add(num);
                inserted = true;
                break;
            }
        }

        if(!inserted) rows.push(new Set([num]));
    }

    return rows.map(row => Array.from(row));
